+    it('should record failed deliveries', async () => {
+      const failSender = mockSender(false, 500);
+      const failHandler = new WebhookHandler(eventBus, failSender);
+      failHandler.registerWebhook('https://example.com/hook', 'order:created');
+
+      await eventBus.emit(makeOrderCreatedEvent());
+
+      const deliveries = failHandler.getDeliveries();
+      expect(deliveries).toHaveLength(1);
+      expect(deliveries[0]?.status).toBe('failure');
+      expect(deliveries[0]?.statusCode).toBe(500);
+    });
