describe('WebhookHandler', () => {
  let eventBus: EventBus;
  let sender: ReturnType<typeof mockSender>;
  let handler: WebhookHandler;

  beforeEach(() => {
    eventBus = new EventBus();
    sender = mockSender();
    handler = new WebhookHandler(eventBus, sender);
    resetWebhookIdCounters();
  });

  describe('webhook registration', () => {
    it('should register a webhook and return the registration', () => {
      const reg = handler.registerWebhook('https://example.com/hook', 'order:created');

      expect(reg.id).toBe('webhook-0001');
      expect(reg.url).toBe('https://example.com/hook');
      expect(reg.eventType).toBe('order:created');
      expect(reg.createdAt).toBeInstanceOf(Date);
    });

    it('should generate sequential webhook IDs', () => {
      const r1 = handler.registerWebhook('https://a.com', 'order:created');
      const r2 = handler.registerWebhook('https://b.com', 'order:status-changed');

      expect(r1.id).toBe('webhook-0001');
      expect(r2.id).toBe('webhook-0002');
    });

    it('should list all registrations', () => {
      handler.registerWebhook('https://a.com', 'order:created');
      handler.registerWebhook('https://b.com', 'order:status-changed');

      expect(handler.getRegistrations()).toHaveLength(2);
    });

    it('should filter registrations by event type', () => {
      handler.registerWebhook('https://a.com', 'order:created');
      handler.registerWebhook('https://b.com', 'order:status-changed');
      handler.registerWebhook('https://c.com', 'order:created');

      expect(handler.getRegistrationsForEvent('order:created')).toHaveLength(2);
      expect(handler.getRegistrationsForEvent('order:status-changed')).toHaveLength(1);
    });

    it('should unregister a webhook by ID', () => {
      const reg = handler.registerWebhook('https://a.com', 'order:created');

      expect(handler.unregisterWebhook(reg.id)).toBe(true);
      expect(handler.getRegistrations()).toHaveLength(0);
    });

    it('should return false when unregistering a non-existent webhook', () => {
      expect(handler.unregisterWebhook('webhook-9999')).toBe(false);
    });
  });

  describe('order:created delivery', () => {
    it('should deliver webhook to registered URL on order created', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      expect(sender.calls).toHaveLength(1);
      expect(sender.calls[0]?.url).toBe('https://example.com/hook');
    });

    it('should include order details in payload', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      const payload = sender.calls[0]!.payload;
      expect(payload.eventType).toBe('order:created');
      expect(payload.orderId).toBe('order-1');
      expect(payload.userId).toBe('user-1');
      expect(payload.total).toBe(20);
      expect(payload.status).toBe('pending');
    });

    it('should not fire for unregistered event types', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:status-changed');

      await eventBus.emit(makeOrderCreatedEvent());

      expect(sender.calls).toHaveLength(0);
    });

    it('should deliver to multiple registered URLs', async () => {
      handler.registerWebhook('https://a.com/hook', 'order:created');
      handler.registerWebhook('https://b.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      expect(sender.calls).toHaveLength(2);
      expect(sender.calls[0]?.url).toBe('https://a.com/hook');
      expect(sender.calls[1]?.url).toBe('https://b.com/hook');
    });
  });

  describe('order:status-changed delivery', () => {
    it('should deliver webhook on status change', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:status-changed');

      await eventBus.emit(makeStatusChangedEvent());

      expect(sender.calls).toHaveLength(1);
      const payload = sender.calls[0]!.payload;
      expect(payload.eventType).toBe('order:status-changed');
      expect(payload.orderId).toBe('order-1');
      expect(payload.previousStatus).toBe('pending');
      expect(payload.newStatus).toBe('confirmed');
    });
  });

  describe('delivery tracking', () => {
    it('should record successful deliveries', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      const deliveries = handler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.id).toBe('delivery-0001');
      expect(deliveries[0]?.status).toBe('success');
      expect(deliveries[0]?.statusCode).toBe(200);
    });

    it('should record failed deliveries', async () => {
      const failSender = mockSender(false, 500);
      const failHandler = new WebhookHandler(eventBus, failSender);
      failHandler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      const deliveries = failHandler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.status).toBe('failure');
      expect(deliveries[0]?.statusCode).toBe(500);
    });

    it('should record null statusCode on network error', async () => {
      const errorSender = mockSender(false, null as unknown as number);
      const errorHandler = new WebhookHandler(eventBus, errorSender);
      errorHandler.registerWebhook('https://example.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      const deliveries = errorHandler.getDeliveries();
      expect(deliveries[0]?.statusCode).toBeNull();
    });

    it('should generate sequential delivery IDs', async () => {
      handler.registerWebhook('https://a.com/hook', 'order:created');
      handler.registerWebhook('https://b.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      const deliveries = handler.getDeliveries();
      expect(deliveries[0]?.id).toBe('delivery-0001');
      expect(deliveries[1]?.id).toBe('delivery-0002');
    });

    it('should filter deliveries by webhook ID', async () => {
      const reg1 = handler.registerWebhook('https://a.com/hook', 'order:created');
      handler.registerWebhook('https://b.com/hook', 'order:created');

      await eventBus.emit(makeOrderCreatedEvent());

      expect(handler.getDeliveriesForWebhook(reg1.id)).toHaveLength(1);
    });

    it('should count deliveries', async () => {
      handler.registerWebhook('https://a.com/hook', 'order:created');

      expect(handler.getDeliveryCount()).toBe(0);

      await eventBus.emit(makeOrderCreatedEvent());

      expect(handler.getDeliveryCount()).toBe(1);
    });
  });

  describe('cleanup', () => {
    it('should clear all registrations and deliveries', async () => {
      handler.registerWebhook('https://example.com/hook', 'order:created');
      await eventBus.emit(makeOrderCreatedEvent());

      handler.clearAll();

      expect(handler.getRegistrations()).toHaveLength(0);
      expect(handler.getDeliveries()).toHaveLength(0);
    });

    it('should not deliver to unregistered webhooks', async () => {
      const reg = handler.registerWebhook('https://example.com/hook', 'order:created');
      handler.unregisterWebhook(reg.id);

      await eventBus.emit(makeOrderCreatedEvent());

      expect(sender.calls).toHaveLength(0);
      expect(handler.getDeliveryCount()).toBe(0);
    });
  });
});

