/**
 * Default sender that performs a real HTTP POST using the global fetch API.
 * Can be replaced in tests with a mock.
 */
const defaultSender: WebhookSender = async (url, payload) => {
  try {
    const response = await (globalThis as Record<string, unknown>).fetch!(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
    }) as { ok: boolean; status: number };
    return { success: response.ok, statusCode: response.status };
  } catch {
    return { success: false, statusCode: null };
  }
};

